// ===== Edit these values =====
const BASE_URL = 'http://host.docker.internal:3002';
const ADMIN_USERNAME = 'test';
const ADMIN_PASSWORD = '10086111';
// API Key from Admin Dashboard > Tokens page (for billing endpoints)
const API_KEY = 'cUmtqY2AYM5d6n2V7twm2zJt1OWY5Dladjf3xfBlJikB8r1e';
const LOG_TYPE = 0;
const LOG_COUNT = 20;
// ===== Don't edit below =====

const cleanBaseUrl = BASE_URL.replace(/\/+$/, '');

return {
  json: {
    base_url: cleanBaseUrl,
    username: ADMIN_USERNAME,
    password: ADMIN_PASSWORD,
    api_key: API_KEY,
    log_type: LOG_TYPE,
    log_count: LOG_COUNT
  }
};

const all = $input.all();
const res = all[0] ? all[0].json : {};

let setCookie = '';
if (all.length > 1 && all[1].json) {
  const h = all[1].json;
  if (h.headers && h.headers['set-cookie']) setCookie = h.headers['set-cookie'];
  else if (h['set-cookie']) setCookie = h['set-cookie'];
}
if (!setCookie && all[0] && all[0].headers && all[0].headers['set-cookie']) {
  setCookie = all[0].headers['set-cookie'];
}
if (!setCookie && res.responseHeaders && res.responseHeaders['set-cookie']) {
  setCookie = res.responseHeaders['set-cookie'];
}

const cm = setCookie.match(/(session=[^;]+)/);
const cookie = cm ? cm[1] : '';

if (!res.success) {
  return { json: { login_success: false, message: res.message || 'Login failed' } };
}

return {
  json: {
    login_success: true,
    session_cookie: cookie,
    user_id: res.data ? res.data.id : null,
    username: res.data ? res.data.username : null
  }
};

const res = $input.first().json;
const data = res.data || {};
const items = data.items || data || [];
const total = data.total || items.length;
const rc = { admin: 0, normal: 0, disabled: 0 };
const gm = {};
(Array.isArray(items) ? items : []).forEach(u => {
  if (u.role >= 2) rc.admin++;
  else rc.normal++;
  if (u.status === 0) rc.disabled++;
  const g = u.group || 'default';
  gm[g] = (gm[g] || 0) + 1;
});
return { json: { _src: 'users', _raw: { success: res.success, message: res.message }, totalUsers: total, admins: rc.admin, normalUsers: rc.normal, enabled: total - rc.disabled, disabled: rc.disabled, groups: gm } };

const res = $input.first().json;
const data = res.data || {};
const modelList = [];
if (data.items) {
  (data.items || []).forEach(m => modelList.push({ id: m.id, name: m.model_name, enabled: m.status === 1 }));
} else if (typeof data === 'object') {
  Object.values(data).forEach(arr => {
    if (Array.isArray(arr)) arr.forEach(m => modelList.push({ id: m.id, name: m.model_name || m.name, enabled: m.status === 1 }));
  });
}
const enabled = modelList.filter(m => m.enabled).length;
return { json: { _src: 'models', _raw: { success: res.success, message: res.message }, totalModels: modelList.length, enabledModels: enabled, disabledModels: modelList.length - enabled, vendorCounts: data.vendor_counts || {} } };

const res = $input.first().json;
const d = res.data || res;
return { json: { _src: 'log_stats', _raw: { success: res.success, message: res.message }, quota: d.quota || 0, rpm: d.rpm || 0, tpm: d.tpm || 0 } };

const res = $input.first().json;
const logs = res.data?.items || res.data || [];
const ms = {};
const cs = {};
let tt = 0;
let tc = 0;
(Array.isArray(logs) ? logs : []).forEach(log => {
  const m = log.model_name || 'unknown';
  const c = log.channel_type || log.channel || 'unknown';
  const t = log.prompt_tokens + log.completion_tokens || 0;
  const cost = log.price || 0;
  ms[m] = (ms[m] || 0) + t;
  cs[c] = (cs[c] || 0) + t;
  tt += t;
  tc += cost;
});
const recent = (Array.isArray(logs) ? logs : []).slice(0, 5).map(log => ({
  time: new Date(log.created_at * 1000).toISOString(),
  model: log.model_name,
  user: log.username,
  tokens: (log.prompt_tokens + log.completion_tokens) || 0,
  cost: log.price || 0
}));
return { json: { _src: 'logs', _raw: { success: res.success, message: res.message }, logCount: logs.length, totalTokens: tt, totalCost: tc.toFixed(4), modelRank: Object.entries(ms).sort((a,b) => b[1]-a[1]).map(([k,v]) => ({ model: k, tokens: v })), channelDist: cs, recentCalls: recent } };

const res = $input.first().json;
const now = Math.floor(Date.now() / 1000);
const until = res.access_until || 0;
const days = until > 0 ? Math.max(0, Math.ceil((until - now) / 86400)) : null;
return { json: { _src: 'sub', _raw: res, softLimit: res.soft_limit_usd, hardLimit: res.hard_limit_usd, sysHardLimit: res.system_hard_limit_usd, expiresAt: until > 0 ? new Date(until * 1000).toISOString() : 'Unlimited', daysLeft: days !== null ? days + ' days' : 'Unlimited', status: days !== null && days <= 0 ? 'Expired' : 'Active' } };

const all = $input.all().map(item => item.json);
const find = src => all.find(d => d._src === src) || {};
const u = find('users');
const m = find('models');
const s = find('log_stats');
const l = find('logs');
const sub = find('sub');
const usage = find('usage');

return {
  json: {
    title: 'New API Admin Dashboard Report',
    generatedAt: new Date().toISOString(),
    userStats: {
      totalUsers: u.totalUsers || 0,
      admins: u.admins || 0,
      normalUsers: u.normalUsers || 0,
      enabled: u.enabled || 0,
      disabled: u.disabled || 0,
      groups: u.groups || {}
    },
    modelStats: {
      totalModels: m.totalModels || 0,
      enabledModels: m.enabledModels || 0,
      disabledModels: m.disabledModels || 0,
      vendorCounts: m.vendorCounts || {}
    },
    modelCallAnalysis: {
      usedQuota: s.quota || 0,
      rpm: s.rpm || 0,
      tpm: s.tpm || 0,
      logCount: l.logCount || 0,
      totalTokens: l.totalTokens || 0,
      totalCost: l.totalCost || '0',
      modelRank: l.modelRank || [],
      channelDist: l.channelDist || {},
      recentCalls: l.recentCalls || []
    },
    billing: {
      softLimitUSD: sub.softLimit || 'N/A',
      hardLimitUSD: sub.hardLimit || 'N/A',
      expiresAt: sub.expiresAt || 'N/A',
      daysLeft: sub.daysLeft || 'N/A',
      status: sub.status || 'N/A',
      totalUsage: usage.totalUsage || 0,
      lineItems: usage.items || []
    },
    debug_APIRaw: {
      users: u._raw || {},
      models: m._raw || {},
      stats: s._raw || {},
      logs: l._raw || {},
      subscription: sub._raw || {},
      usage: usage._raw || {}
    }
  }
};
